    var dg = dirtBase.getContext('2d');
    dg.setTransform(GDPR, 0, 0, GDPR, 0, 0);
    dg.clearRect(0, 0, GW, GH);

    /* köşeden sızan soğuk parlama (referanstaki mavi ton) */
    var bl = dg.createRadialGradient(GW * .88, GH * .72, 10, GW * .88, GH * .72, GW * .5);
    bl.addColorStop(0, 'rgba(90,140,200,.05)');
    bl.addColorStop(1, 'rgba(90,140,200,0)');
    dg.fillStyle = bl; dg.fillRect(0, 0, GW, GH);
    var tl = dg.createRadialGradient(GW * .1, GH * .05, 10, GW * .1, GH * .05, GW * .4);
    tl.addColorStop(0, 'rgba(240,246,240,.05)');
    tl.addColorStop(1, 'rgba(240,246,240,0)');
    dg.fillStyle = tl; dg.fillRect(0, 0, GW, GH);

    /* dairesel silme izleri */
    for(var a = 0; a < 7; a++){
      var cxA = GW * (.2 + Math.random() * .6);
      var cyA = GH * (.2 + Math.random() * .6);
      var rA = 80 + Math.random() * GH * .8;
      dg.strokeStyle = 'rgba(220,230,235,' + (.015 + Math.random() * .02) + ')';
      dg.lineWidth = .7;
      var s0 = Math.random() * 6.28, s1 = s0 + 1 + Math.random() * 2.5;
      dg.beginPath(); dg.arc(cxA, cyA, rA, s0, s1); dg.stroke();
    }
    /* kıl çizikler */
    for(var s = 0; s < 14; s++){
      var x0 = Math.random() * GW, y0 = Math.random() * GH;
      var ang = Math.random() * 6.28, len = 60 + Math.random() * 260;
      var x1 = x0 + Math.cos(ang) * len, y1 = y0 + Math.sin(ang) * len;
      dg.strokeStyle = 'rgba(225,235,240,' + (.028 + Math.random() * .045) + ')';
      dg.lineWidth = Math.random() < .3 ? 1 : .6;
      dg.beginPath(); dg.moveTo(x0, y0);
      dg.quadraticCurveTo((x0 + x1) / 2 + (Math.random() - .5) * 30,
                          (y0 + y1) / 2 + (Math.random() - .5) * 30, x1, y1);
      dg.stroke();
    }
    /* nokta/toz YOK — noktalar kara zeminde yıldız gibi okunur; cam hissi çizgisel izlerden gelir */
    DUST = [];
    /* ana köşegen çizik: parlamaların gezindiği hat */
