      oc.width = MASKW; oc.height = MASKH;
      var og = oc.getContext('2d');
      og.scale(MASKW / 1745.9, MASKH / 1685.23);
      og.fillStyle = '#fff';
      og.fill(new Path2D(LOGO_P1));
      og.fill(new Path2D(LOGO_P2));
      var d = og.getImageData(0, 0, MASKW, MASKH).data;
      var on = function(x, y){
        if(x < 0 || y < 0 || x >= MASKW || y >= MASKH) return false;
        return d[(y * MASKW + x) * 4 + 3] > 60;
      };
      for(var y = 0; y < MASKH; y++){
        for(var x = 0; x < MASKW; x++){
          if(!on(x, y)) continue;
          logoPts.push({ x: x, y: y });
          if(!on(x-1,y) || !on(x+1,y) || !on(x,y-1) || !on(x,y+1)){
            logoEdge[y * MASKW + x] = true;
          }
        }
      }
